"use strict";parserFactory.register("idleturtle-translations.com",()=>new IdleturtletranslationsParser);class IdleturtletranslationsParser extends Parser{constructor(){super()}async getChapterUrls(t){let e=t.querySelector("div.pt-cv-wrapper");return util.hyperlinksToChapterList(e)}findContent(t){return t.querySelector("div[itemprop='articleBody']")}extractTitleImpl(t){return t.querySelector("article h3")}findChapterTitle(t){return t.querySelector("article h1")}preprocessRawDom(t){let e=this.findContent(t),r=(new FootnoteExtractor).scriptElementsToFootnotes(t);this.moveFootnotes(t,e,r)}findCoverImageUrl(t){return util.getFirstImgSrc(t,"article")}}